parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "action_taken": {
      "type": "string",
      "description": "Description of the action performed or to be performed"
    },
    "needs_approval": {
      "type": "boolean",
      "description": "Whether user approval is required before executing the action"
    },
    "approval_details": {
      "type": ["string", "null"],
      "description": "Specific details about what needs approval (API calls to make, event details). Null if no approval needed."
    },
    "events_found": {
      "type": "array",
      "description": "List of relevant calendar events found",
      "items": {
        "type": "object",
        "properties": {
          "id": {
            "type": "string",
            "description": "Event ID"
          },
          "title": {
            "type": "string",
            "description": "Event title"
          },
          "start_time": {
            "type": "string",
            "description": "Event start time in ISO format"
          },
          "end_time": {
            "type": "string",
            "description": "Event end time in ISO format"
          },
          "duration": {
            "type": "number",
            "description": "Duration in minutes"
          }
        }
      }
    },
    "message": {
      "type": "string",
      "description": "User-friendly message summarizing the result or action"
    },
    "success": {
      "type": "boolean",
      "description": "Whether the operation was successful"
    }
  },
  "required": ["action_taken", "needs_approval", "message", "success"]
}

parameters.jsonBody:
={
  "jsonBody": "=📅 Calendar Action Requires Approval

Action: {{ $json.output.action_taken }}

Details: {{ $json.output.approval_details }}

Message: {{ $json.output.message }}

{{ $json.output.events_found && $json.output.events_found.length > 0 ? 'Events Affected:
' + $json.output.events_found.map(e => '• ' + e.title + ' (' + e.start_time + ')').join('
') + '

' : '' }}Reply with:
✅ 'approved' to proceed
❌ 'denied' to cancel"
}

=❌ Calendar Action Failed

Action: {{ $json.output.action_taken }}

Message: {{ $json.output.message }}

Please try again or rephrase your request.

